fn make_test_issues(count: usize) -> Vec<Issue> {
    (0..count).map(|i| Issue {
        id: format!("test-{}", i),
        title: format!("Test issue {}", i),
        status: Status::Open,
        priority: Priority::MEDIUM,
        issue_type: IssueType::Task,
        ..Default::default()
    }).collect()
}

#[test]
fn test_table_renders_all_issues() {
    let issues = make_test_issues(5);
    let ctx = OutputContext::plain();
    let table = IssueTable::new(&issues, &ctx);
    let output = table.render_to_string().unwrap();
    for issue in &issues {
        assert!(output.contains(&issue.id), "Should contain {}", issue.id);
    }
}

